SELECT sc."content", COUNT(sc."content") AS "frequency", LISTAGG(l."language"::STRING, ', ') WITHIN GROUP (ORDER BY l."language") AS "languages" FROM "GITHUB_REPOS"."PUBLIC"."SAMPLE_CONTENTS" sc JOIN "GITHUB_REPOS"."PUBLIC"."LANGUAGES" l ON sc."sample_repo_name" = l."repo_name" WHERE sc."content" IS NOT NULL AND sc."content" != '' AND sc."content" NOT LIKE '#%' AND sc."content" NOT LIKE '//%' AND sc."sample_path" ILIKE '%README.md%' GROUP BY sc."content" ORDER BY "frequency" DESC
